class Solution:
    def numberOfPairs(self, nums):
        remaining = list(nums)
        pairs = 0
        changed = True
        while changed:
            changed = False
            for i in range(len(remaining)):
                for j in range(i + 1, len(remaining)):
                    if remaining[i] == remaining[j]:
                        remaining.pop(j)
                        remaining.pop(i)
                        pairs += 1
                        changed = True
                        break
                if changed:
                    break
        return [pairs, len(remaining)]

