var numberOfPairs = function(nums) {
    const c = new Map();
    for (const x of nums) c.set(x, (c.get(x) || 0) + 1);
    let pairs = 0, leftover = 0;
    for (const v of c.values()) {
        pairs += Math.floor(v / 2);
        leftover += v % 2;
    }
    return [pairs, leftover];
};
